frame_eqs:
q1 = aspectx;
q2 = aspecty;
wave_a = 0;
v = 0.5;
j1 = j1*0.95 + sqr(bass*4)*v;
j2 = j2*0.95 + sqr(mid*4)*v;
j3 = j3*0.95 + sqr(treb*4)*v;

n = n + j1*0.0052;
n1 = n1 + j2*0.00473;
n2 = n2 + j3*0.0052;


q3 = n*0.01; // passing the 3 room angles
q4 = n1*0.01;
q5 = n2*0.01;


// lorenz-attractor calc
a = 10;
b = 28;
c = 8/3;
dx1 = a*(y1-x1);
dy1 = x1*(b-z1)-y1;
dz1 = x1*y1-c*z1;
d = 1;
dd = sqrt(dx1*dx1 + dy1*dy1 + dz1*dz1);
x1 = x1 + d*dx1/dd;
y1 = y1 + d*dy1/dd;
z1 = z1 + d*dz1/dd;

q11 = x1;
q12 = y1;
q13 = z1;
q14 = a;
q15 = b;
q16 = c;
q17 = d;

wave_0_per_point:
// lorenz-attractor calc
xx1 = if(equal(sample,0),q11,xx1);
yy1 = if(equal(sample,0),q12,yy1);
zz1 = if(equal(sample,0),q13,zz1);
dx1 = q14*(yy1-xx1);
dy1 = xx1*(q15-zz1)-yy1;
dz1 = xx1*yy1-q16*zz1;
xx1 = xx1 + q17*dx1;
yy1 = yy1 + q17*dy1;
zz1 = zz1 + q17*dz1;

// 3D model coordinates
my_x = xx1*0.1;
my_y = yy1*0.1;
my_z = zz1*0.1 - 3;


d = 5; // distance of the camera (on the z-axis) to the origin
zoom = 0.4;

// solid angles
w1 = q2;
w2 = q3;
w3 = q4;

// rotations
x1 = cos(w1)*my_x + sin(w1)*my_y;
y1 = -sin(w1)*my_x + cos(w1)*my_y;
z1 = my_z;

x2 = cos(w2)*x1 + sin(w2)*z1;
z2 = -sin(w2)*x1 + cos(w2)*z1;
y2 = y1;

y3 = cos(w3)*y2 + sin(w3)*z2;
z3 = -sin(w3)*y2 + cos(w3)*z2;
x3 = x2;

// perspective calculation

l = sqrt(x3*x3 + y3*y3);
w = atan2(x3,y3);
p = tan(asin(1) + atan2(d+z3,l));
d = sqrt(x3*x3 + y3*y3 + (z3+d)*(z3+d));

my_x = zoom*sin(w)*p;
my_y = zoom*cos(w)*p;

x = 0.5 + my_x;
y = 0.5 + my_y;

